package main
import ("context";"encoding/json";"net/http";"github.com/go-chi/chi/v5";"github.com/jackc/pgx/v5/pgxpool")
func main(){db,_:=pgxpool.New(context.Background(),"postgres://postgres:postgres@postgres:5432/hypercompute?sslmode=disable");r:=chi.NewRouter();r.Get("/health",func(w http.ResponseWriter,r *http.Request){w.Write([]byte("ok"))});r.Get("/metrics",func(w http.ResponseWriter,r *http.Request){w.Write([]byte("settlement_up 1"))});r.Post("/earnings",func(w http.ResponseWriter,r *http.Request){var b map[string]any;json.NewDecoder(r.Body).Decode(&b);amt:=b["amount"].(float64)*0.65;_,_=db.Exec(r.Context(),"insert into provider_earnings(node_id,billing_request_id,amount,status,available_at,created_at) values($1,$2,$3,'PENDING',now()+interval '7 day',now())",b["node_id"],b["request_id"],amt);json.NewEncoder(w).Encode(map[string]any{"ok":true})});http.ListenAndServe(":8087",r)}
